import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(point1, point2):
        return np.sqrt(np.sum((point1 - point2) ** 2))

    best_node = None
    min_time_cost = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_distance(cur_truck_pos, customer_pos) / truck_speed
        arrival_time = current_time + travel_time
        start_window, end_window = time_windows[i]

        if arrival_time > end_window:
            time_penalty = (arrival_time - end_window) * 100  # Large penalty if past time window
        elif arrival_time < start_window:
            time_penalty = start_window - arrival_time  # Time at which the truck needs to wait
        else:
            time_penalty = 0  # Within time window

        time_cost = travel_time + time_penalty

        if time_cost < min_time_cost:
            min_time_cost = time_cost
            best_node = i

    return best_node
